def scheme_eval(expr, env):
    if isinstance(expr, int):
        return expr
    if isinstance(expr, str):
        return env[expr]

    first = expr[0]
    rest = expr[1:]

    if first == "define":
        name = rest[0]
        value = scheme_eval(rest[1], env)
        env[name] = value
        return None

    procedure = scheme_eval(first, env)
    args = [scheme_eval(operand, env) for operand in rest]
    return scheme_apply(procedure, args, env)


def scheme_apply(procedure, args, env):
    return procedure(*args)


global_env = {
    "+": lambda x, y: x + y,
    "*": lambda x, y: x * y,
}

print(scheme_eval(["+", 2, ["*", 3, 4]], global_env))
scheme_eval(["define", "x", 10], global_env)
print(scheme_eval("x", global_env))
